def solve(s: String): Array[String] = {
  import scala.collection.mutable.HashSet
  val segments = scala.collection.mutable.ArrayBuffer[String]()
  val seen = HashSet[String]()
  var i = 0
  while (i < s.length) {
    var current = ""
    var j = i
    while (j < s.length) {
      current += s(j)
      if (!seen.contains(current)) {
        seen += current
        segments += current
        i = j + 1
        j = s.length // break the loop
      } else {
        j += 1
      }
    }
  }
  segments.toArray
}
